-- ============================================================================
-- Layer 1: Physical KG Tables + Cross-System Entity Resolution Load
-- HEALTHCARE_ONTOLOGY  (hand-authored; replaces naive generator output)
-- Target: CLINICAL_EMR.ONTOLOGY  (sources span 3 databases)
-- ============================================================================
CREATE SCHEMA IF NOT EXISTS CLINICAL_EMR.ONTOLOGY;
USE SCHEMA CLINICAL_EMR.ONTOLOGY;

-- ---- KG storage ------------------------------------------------------------
CREATE OR REPLACE TABLE KG_NODE (
    NODE_ID      STRING NOT NULL,
    NODE_TYPE    STRING NOT NULL,
    NAME         STRING,
    PROPS        VARIANT,
    TS_INGESTED  TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP(),
    CONSTRAINT PK_KG_NODE PRIMARY KEY (NODE_ID)
) CLUSTER BY (NODE_TYPE);

CREATE OR REPLACE TABLE KG_EDGE (
    EDGE_ID         STRING NOT NULL,
    SRC_ID          STRING NOT NULL,
    DST_ID          STRING NOT NULL,
    EDGE_TYPE       STRING NOT NULL,
    WEIGHT          FLOAT DEFAULT 1.0,
    PROPS           VARIANT,
    EFFECTIVE_START DATE,
    EFFECTIVE_END   DATE,
    TS_INGESTED     TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP(),
    CONSTRAINT PK_KG_EDGE PRIMARY KEY (EDGE_ID)
) CLUSTER BY (EDGE_TYPE, SRC_ID, DST_ID);

-- ---- Canonicalization helper: dotted ICD-10 --------------------------------
CREATE OR REPLACE FUNCTION FN_ICD10_DOTTED(code STRING)
RETURNS STRING
AS $$
  CASE WHEN code IS NULL THEN NULL
       WHEN POSITION('.' IN code) > 0 THEN UPPER(TRIM(code))
       WHEN LENGTH(TRIM(code)) > 3 THEN LEFT(UPPER(TRIM(code)),3)||'.'||SUBSTR(UPPER(TRIM(code)),4)
       ELSE UPPER(TRIM(code)) END
$$;

-- ============================================================================
-- STAGING / RESOLUTION VIEWS  (identity crosswalks)
-- ============================================================================

-- claims MEMBER_ID -> canonical MRN  (strong: INS_MEMBER_ID)
CREATE OR REPLACE VIEW STG_MAP_MEMBER AS
SELECT m.MEMBER_ID, p.MRN
FROM PAYER_CLAIMS.CLAIMS.MEMBER m
JOIN CLINICAL_EMR.EHR.PATIENT_MASTER p ON p.INS_MEMBER_ID = m.MEMBER_ID;

-- pharmacy RX_MEMBER_ID -> canonical MRN  (SSN, else DOB + last name; nickname-tolerant)
CREATE OR REPLACE VIEW STG_MAP_RX AS
SELECT s.RX_MEMBER_ID,
       COALESCE(p_ssn.MRN, p_nd.MRN) AS MRN,
       IFF(p_ssn.MRN IS NOT NULL,'SSN','NAME_DOB') AS MATCH_BASIS
FROM PHARMACY_OPS.RX.SUBSCRIBER s
LEFT JOIN CLINICAL_EMR.EHR.PATIENT_MASTER p_ssn
       ON s.PATIENT_SSN IS NOT NULL AND p_ssn.SSN = s.PATIENT_SSN
LEFT JOIN CLINICAL_EMR.EHR.PATIENT_MASTER p_nd
       ON s.PATIENT_SSN IS NULL
      AND p_nd.DOB = s.DOB
      AND UPPER(p_nd.LAST_NAME) = UPPER(SPLIT_PART(s.PATIENT_NAME,' ',-1));

-- local PHYSICIAN_ID -> universal NPI
CREATE OR REPLACE VIEW STG_PHYS_LOCAL AS
SELECT PHYSICIAN_ID, NPI FROM CLINICAL_EMR.EHR.PHYSICIAN;

-- EMR DRUG_NAME -> RxNorm via text match (generic leading word + strength number)
CREATE OR REPLACE VIEW STG_DRUG_TEXT_MATCH AS
SELECT d.DRUG_NAME, MIN(n.RXNORM_CODE) AS RXNORM_CODE
FROM (SELECT DISTINCT DRUG_NAME FROM CLINICAL_EMR.EHR.MEDICATION) d
JOIN PHARMACY_OPS.RX.NDC_PRODUCT n
  ON UPPER(SPLIT_PART(d.DRUG_NAME,' ',1)) = UPPER(SPLIT_PART(n.GENERIC_NAME,' ',1))
 AND ( REGEXP_SUBSTR(d.DRUG_NAME,'[0-9]+') IS NULL
       OR REGEXP_SUBSTR(d.DRUG_NAME,'[0-9]+') = REGEXP_SUBSTR(n.STRENGTH,'[0-9]+') )
GROUP BY d.DRUG_NAME;

-- NDC -> RxNorm crosswalk (pharmacy fills)
CREATE OR REPLACE VIEW STG_NDC_RXNORM AS
SELECT NDC, RXNORM_CODE FROM PHARMACY_OPS.RX.NDC_PRODUCT;

-- Canonical patient attributes (anchored on EMR MRN, enriched w/ system presence)
CREATE OR REPLACE VIEW STG_PATIENT AS
SELECT
    p.MRN                              AS PATIENT_KEY,
    p.MRN,
    p.INS_MEMBER_ID                    AS MEMBER_ID,
    rx.RX_MEMBER_ID,
    p.SSN,
    p.FIRST_NAME||' '||p.LAST_NAME     AS FULL_NAME,
    p.FIRST_NAME, p.LAST_NAME, p.DOB,
    p.SEX                              AS GENDER,
    p.CITY, p.STATE, p.ZIP, p.PHONE,
    p.PCP_NPI,
    'EHR'
      || IFF(mm.MRN IS NOT NULL, ',CLAIMS','')
      || IFF(rx.MRN IS NOT NULL, ',PHARMACY','')   AS SOURCE_SYSTEMS
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p
LEFT JOIN STG_MAP_MEMBER mm ON mm.MRN = p.MRN
LEFT JOIN STG_MAP_RX    rx  ON rx.MRN = p.MRN;

-- Canonical practitioner (anchored on NPI; three name spellings + specialties)
CREATE OR REPLACE VIEW STG_PRACTITIONER AS
SELECT
    ph.NPI,
    ph.FULL_NAME                       AS FULL_NAME,       -- EMR canonical display
    ph.FULL_NAME                       AS NAME_EMR,
    rp.PROVIDER_NAME                   AS NAME_CLAIMS,
    pr.PRESCRIBER_NAME                 AS NAME_PHARMACY,
    ph.SPECIALTY                       AS SPECIALTY,        -- EMR canonical wins
    rp.PROVIDER_TYPE                   AS SPECIALTY_RAW_CLAIMS,
    ph.PHYSICIAN_ID                    AS LOCAL_PHYSICIAN_ID,
    ph.DEPT_ID,
    pr.DEA_NUMBER,
    'EHR'
      || IFF(rp.RENDERING_NPI IS NOT NULL, ',CLAIMS','')
      || IFF(pr.PRESCRIBER_ID IS NOT NULL, ',PHARMACY','') AS SOURCE_SYSTEMS
FROM CLINICAL_EMR.EHR.PHYSICIAN ph
LEFT JOIN PAYER_CLAIMS.CLAIMS.RENDERING_PROVIDER rp ON rp.RENDERING_NPI = ph.NPI
LEFT JOIN PHARMACY_OPS.RX.PRESCRIBER pr            ON pr.PRESCRIBER_ID  = ph.NPI;

-- Distinct facilities
CREATE OR REPLACE VIEW STG_FACILITY AS
SELECT DISTINCT FACILITY_NAME,
       'FAC:'||UPPER(REPLACE(REPLACE(FACILITY_NAME,' ','_'),'''','')) AS FACILITY_KEY
FROM CLINICAL_EMR.EHR.DEPARTMENT
WHERE FACILITY_NAME IS NOT NULL;

-- Distinct payers (union across all three systems, normalized)
CREATE OR REPLACE VIEW STG_PAYER AS
SELECT PAYER_NAME,
       'PAYER:'||UPPER(REPLACE(PAYER_NAME,' ','_')) AS PAYER_ID,
       LISTAGG(DISTINCT SRC, ',') WITHIN GROUP (ORDER BY SRC) AS SOURCE_SYSTEMS
FROM (
    SELECT TRIM(PLAN_NAME) AS PAYER_NAME, 'CLAIMS' SRC FROM PAYER_CLAIMS.CLAIMS.MEMBER WHERE PLAN_NAME IS NOT NULL
    UNION ALL
    SELECT TRIM(INS_PAYER_NAME), 'EHR' FROM CLINICAL_EMR.EHR.PATIENT_MASTER WHERE INS_PAYER_NAME IS NOT NULL
    UNION ALL
    SELECT TRIM(PLAN_NAME), 'CLAIMS_LINE' FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE WHERE PLAN_NAME IS NOT NULL
)
GROUP BY PAYER_NAME;

-- Medication order RxNorm resolution (direct else text-recovered)
CREATE OR REPLACE VIEW STG_MEDREQUEST AS
SELECT
    m.MED_ORDER_ID, m.MRN AS PATIENT_KEY, pl.NPI AS PHYSICIAN_NPI,
    m.ORDER_DATE, m.DRUG_NAME, m.RXNORM_CODE,
    COALESCE(m.RXNORM_CODE, tx.RXNORM_CODE) AS RXNORM_RESOLVED,
    (m.RXNORM_CODE IS NULL)                 AS RXNORM_WAS_NULL,
    m.SIG, m.QUANTITY, m.REFILLS
FROM CLINICAL_EMR.EHR.MEDICATION m
LEFT JOIN STG_PHYS_LOCAL pl      ON pl.PHYSICIAN_ID = m.PHYSICIAN_ID
LEFT JOIN STG_DRUG_TEXT_MATCH tx ON tx.DRUG_NAME    = m.DRUG_NAME;

-- Pharmacy dispense resolution (patient + NDC->RxNorm)
CREATE OR REPLACE VIEW STG_DISPENSE AS
SELECT
    f.FILL_ID, f.RX_MEMBER_ID, rx.MRN AS PATIENT_KEY, f.PRESCRIBER_ID AS PRESCRIBER_NPI,
    f.NDC, nr.RXNORM_CODE, f.DRUG_DESC, f.WRITTEN_DATE, f.FILL_DATE,
    f.DAYS_SUPPLY, f.QUANTITY, f.FILL_STATUS
FROM PHARMACY_OPS.RX.PHARMACY_FILL f
LEFT JOIN STG_MAP_RX rx     ON rx.RX_MEMBER_ID = f.RX_MEMBER_ID
LEFT JOIN STG_NDC_RXNORM nr ON nr.NDC          = f.NDC;

-- Claim header aggregation (from overloaded CLAIMS_LINE)
CREATE OR REPLACE VIEW STG_CLAIM AS
SELECT
    cl.CLAIM_ID,
    MAX(cl.MEMBER_ID)        AS MEMBER_ID,
    MAX(cl.SUBSCRIBER_ID)    AS SUBSCRIBER_ID,
    MAX(mm.MRN)              AS PATIENT_KEY,
    MAX(cl.PLAN_NAME)        AS PLAN_NAME,
    MAX(cl.RENDERING_NPI)    AS RENDERING_NPI,
    MAX(cl.SERVICE_DATE)     AS SERVICE_DATE,
    MAX(cl.POS_CODE)         AS POS_CODE,
    MAX(cl.CLAIM_STATUS)     AS CLAIM_STATUS,
    SUM(cl.CHARGE_AMT)       AS TOTAL_CHARGE,
    SUM(cl.PAID_AMT)         AS TOTAL_PAID
FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE cl
LEFT JOIN STG_MAP_MEMBER mm ON mm.MEMBER_ID = cl.MEMBER_ID
GROUP BY cl.CLAIM_ID;

-- ============================================================================
-- KG_NODE LOADS  (one canonical node per resolved entity; lowercase PROPS keys)
-- ============================================================================

-- Patient
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'PT:'||PATIENT_KEY, 'Patient', FULL_NAME,
  OBJECT_CONSTRUCT('mrn',MRN,'member_id',MEMBER_ID,'rx_member_id',RX_MEMBER_ID,'ssn',SSN,
    'full_name',FULL_NAME,'first_name',FIRST_NAME,'last_name',LAST_NAME,'dob',TO_VARCHAR(DOB),
    'gender',GENDER,'city',CITY,'state',STATE,'zip',ZIP,'phone',PHONE,'source_systems',SOURCE_SYSTEMS)
FROM STG_PATIENT;

-- Practitioner
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'PR:'||NPI, 'Practitioner', FULL_NAME,
  OBJECT_CONSTRUCT('npi',NPI,'full_name',FULL_NAME,'name_emr',NAME_EMR,'name_claims',NAME_CLAIMS,
    'name_pharmacy',NAME_PHARMACY,'specialty',SPECIALTY,'specialty_raw_claims',SPECIALTY_RAW_CLAIMS,
    'local_physician_id',LOCAL_PHYSICIAN_ID,'dept_id',DEPT_ID,'dea_number',DEA_NUMBER,'source_systems',SOURCE_SYSTEMS)
FROM STG_PRACTITIONER;

-- RelatedPerson (next-of-kin; resolved to an existing patient by name where possible)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'RP:'||p.MRN, 'RelatedPerson', p.KIN_NAME,
  OBJECT_CONSTRUCT('kin_name',p.KIN_NAME,'kin_relation',p.KIN_RELATION,'kin_phone',p.KIN_PHONE,
    'patient_key',p.MRN,'resolved_patient_key',rp.MRN)
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p
LEFT JOIN CLINICAL_EMR.EHR.PATIENT_MASTER rp
       ON UPPER(rp.FIRST_NAME||' '||rp.LAST_NAME) = UPPER(p.KIN_NAME) AND rp.MRN <> p.MRN
WHERE p.KIN_NAME IS NOT NULL;

-- Payer
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT PAYER_ID, 'Payer', PAYER_NAME,
  OBJECT_CONSTRUCT('payer_name',PAYER_NAME,'source_systems',SOURCE_SYSTEMS)
FROM STG_PAYER;

-- Facility
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT FACILITY_KEY, 'Facility', FACILITY_NAME,
  OBJECT_CONSTRUCT('facility_key',FACILITY_KEY,'facility_name',FACILITY_NAME)
FROM STG_FACILITY;

-- Location (department)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'LOC:'||d.DEPT_ID, 'Location', d.DEPT_NAME,
  OBJECT_CONSTRUCT('dept_id',d.DEPT_ID,'dept_name',d.DEPT_NAME,'facility_name',d.FACILITY_NAME,
    'facility_key','FAC:'||UPPER(REPLACE(REPLACE(d.FACILITY_NAME,' ','_'),'''','')),
    'address',d.ADDRESS,'city',d.CITY,'state',d.STATE,'zip',d.ZIP)
FROM CLINICAL_EMR.EHR.DEPARTMENT d;

-- ServiceSetting (CMS POS)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'SVC:'||POS_CODE, 'ServiceSetting', POS_DESCRIPTION,
  OBJECT_CONSTRUCT('pos_code',POS_CODE,'pos_description',POS_DESCRIPTION)
FROM PAYER_CLAIMS.CLAIMS.PLACE_OF_SERVICE;

-- Encounter
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'ENC:'||v.VISIT_ID, 'Encounter', v.VISIT_ID,
  OBJECT_CONSTRUCT('visit_id',v.VISIT_ID,'visit_date',TO_VARCHAR(v.VISIT_DATE),'visit_type',v.VISIT_TYPE,
    'status',v.STATUS,'patient_key',v.MRN,'npi',pl.NPI,'dept_id',v.DEPT_ID,'primary_icd10',v.PRIMARY_ICD10)
FROM CLINICAL_EMR.EHR.VISIT v
LEFT JOIN STG_PHYS_LOCAL pl ON pl.PHYSICIAN_ID = v.PHYSICIAN_ID;

-- Claim
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'CLM:'||CLAIM_ID, 'Claim', CLAIM_ID,
  OBJECT_CONSTRUCT('claim_id',CLAIM_ID,'member_id',MEMBER_ID,'subscriber_id',SUBSCRIBER_ID,'patient_key',PATIENT_KEY,
    'plan_name',PLAN_NAME,'rendering_npi',RENDERING_NPI,'service_date',TO_VARCHAR(SERVICE_DATE),'pos_code',POS_CODE,
    'claim_status',CLAIM_STATUS,'total_charge',TOTAL_CHARGE,'total_paid',TOTAL_PAID)
FROM STG_CLAIM;

-- ClaimLine
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'CLL:'||cl.CLAIM_ID||':'||cl.LINE_NO, 'ClaimLine', cl.CPT_DESC,
  OBJECT_CONSTRUCT('claim_id',cl.CLAIM_ID,'line_no',cl.LINE_NO,'cpt_code',cl.CPT_CODE,'cpt_desc',cl.CPT_DESC,
    'dx_code',cl.DX_CODE,'dx_canonical',FN_ICD10_DOTTED(cl.DX_CODE),
    'charge_amt',cl.CHARGE_AMT,'allowed_amt',cl.ALLOWED_AMT,'paid_amt',cl.PAID_AMT)
FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE cl;

-- MedicationRequest
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'MR:'||MED_ORDER_ID, 'MedicationRequest', DRUG_NAME,
  OBJECT_CONSTRUCT('med_order_id',MED_ORDER_ID,'patient_key',PATIENT_KEY,'physician_npi',PHYSICIAN_NPI,
    'order_date',TO_VARCHAR(ORDER_DATE),'drug_name',DRUG_NAME,'rxnorm_code',RXNORM_CODE,
    'rxnorm_resolved',RXNORM_RESOLVED,'rxnorm_was_null',RXNORM_WAS_NULL,'sig',SIG,'quantity',QUANTITY,'refills',REFILLS)
FROM STG_MEDREQUEST;

-- MedicationDispense
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'MD:'||FILL_ID, 'MedicationDispense', DRUG_DESC,
  OBJECT_CONSTRUCT('fill_id',FILL_ID,'rx_member_id',RX_MEMBER_ID,'patient_key',PATIENT_KEY,'prescriber_npi',PRESCRIBER_NPI,
    'ndc',NDC,'rxnorm_code',RXNORM_CODE,'drug_desc',DRUG_DESC,'written_date',TO_VARCHAR(WRITTEN_DATE),
    'fill_date',TO_VARCHAR(FILL_DATE),'days_supply',DAYS_SUPPLY,'quantity',QUANTITY,'fill_status',FILL_STATUS)
FROM STG_DISPENSE;

-- Observation: vitals (from VISIT, unpivoted via UNION ALL)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'OBS:V:'||VISIT_ID||':'||code, 'Observation', obs_name,
  OBJECT_CONSTRUCT('obs_kind','VITAL','obs_code',code,'obs_name',obs_name,'value_num',val,'unit',unit,
    'obs_date',TO_VARCHAR(VISIT_DATE),'patient_key',MRN,'visit_id',VISIT_ID)
FROM (
  SELECT VISIT_ID, VISIT_DATE, MRN, 'BP_SYSTOLIC' code, 'Systolic Blood Pressure' obs_name, BP_SYSTOLIC val, 'mmHg' unit FROM CLINICAL_EMR.EHR.VISIT
  UNION ALL SELECT VISIT_ID, VISIT_DATE, MRN, 'BP_DIASTOLIC','Diastolic Blood Pressure', BP_DIASTOLIC, 'mmHg' FROM CLINICAL_EMR.EHR.VISIT
  UNION ALL SELECT VISIT_ID, VISIT_DATE, MRN, 'WEIGHT_KG','Body Weight', WEIGHT_KG, 'kg' FROM CLINICAL_EMR.EHR.VISIT
  UNION ALL SELECT VISIT_ID, VISIT_DATE, MRN, 'A1C_PCT','Hemoglobin A1c', A1C_PCT, '%' FROM CLINICAL_EMR.EHR.VISIT
)
WHERE val IS NOT NULL;

-- Observation: labs (from LAB_RESULTS, unpivoted via UNION ALL)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'OBS:L:'||LAB_ID||':'||code, 'Observation', obs_name,
  OBJECT_CONSTRUCT('obs_kind','LAB','obs_code',code,'obs_name',obs_name,'value_num',val,'unit',unit,
    'obs_date',TO_VARCHAR(COLLECT_DATE),'patient_key',MRN,'visit_id',NULL)
FROM (
  SELECT LAB_ID, COLLECT_DATE, MRN, 'GLUCOSE_MGDL' code, 'Glucose' obs_name, GLUCOSE_MGDL val, 'mg/dL' unit FROM CLINICAL_EMR.EHR.LAB_RESULTS
  UNION ALL SELECT LAB_ID, COLLECT_DATE, MRN, 'HBA1C_PCT','Hemoglobin A1c', HBA1C_PCT, '%' FROM CLINICAL_EMR.EHR.LAB_RESULTS
  UNION ALL SELECT LAB_ID, COLLECT_DATE, MRN, 'LDL_MGDL','LDL Cholesterol', LDL_MGDL, 'mg/dL' FROM CLINICAL_EMR.EHR.LAB_RESULTS
  UNION ALL SELECT LAB_ID, COLLECT_DATE, MRN, 'CREATININE_MGDL','Creatinine', CREATININE_MGDL, 'mg/dL' FROM CLINICAL_EMR.EHR.LAB_RESULTS
  UNION ALL SELECT LAB_ID, COLLECT_DATE, MRN, 'EGFR','eGFR', EGFR, 'mL/min/1.73m2' FROM CLINICAL_EMR.EHR.LAB_RESULTS
)
WHERE val IS NOT NULL;

-- Condition (canonical dotted ICD-10; union EMR problem list + visit + claims, prefer described)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'CND:'||icd_dotted, 'Condition', ANY_VALUE(icd_desc),
  OBJECT_CONSTRUCT('icd10_dotted',icd_dotted,'icd10_nodot',REPLACE(icd_dotted,'.',''),
    'icd10_desc',ANY_VALUE(icd_desc),'snomed_code',ANY_VALUE(snomed),
    'source_systems',LISTAGG(DISTINCT src,',') WITHIN GROUP (ORDER BY src))
FROM (
    SELECT FN_ICD10_DOTTED(ICD10_CODE) icd_dotted, ICD10_DESC icd_desc, SNOMED_CODE snomed, 'PROBLEM_LIST' src
      FROM CLINICAL_EMR.EHR.PROBLEM_LIST WHERE ICD10_CODE IS NOT NULL
    UNION ALL
    SELECT FN_ICD10_DOTTED(PRIMARY_ICD10), NULL, NULL, 'VISIT'
      FROM CLINICAL_EMR.EHR.VISIT WHERE PRIMARY_ICD10 IS NOT NULL
    UNION ALL
    SELECT FN_ICD10_DOTTED(DX_CODE), CPT_DESC_IGNORE, NULL, 'CLAIMS_LINE'
      FROM (SELECT DISTINCT DX_CODE, NULL CPT_DESC_IGNORE FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE WHERE DX_CODE IS NOT NULL)
)
GROUP BY icd_dotted;

-- Procedure (distinct CPT)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'PROC:'||CPT_CODE, 'Procedure', ANY_VALUE(CPT_DESC),
  OBJECT_CONSTRUCT('cpt_code',CPT_CODE,'cpt_desc',ANY_VALUE(CPT_DESC))
FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE WHERE CPT_CODE IS NOT NULL
GROUP BY CPT_CODE;

-- Medication (canonical RxNorm from NDC_PRODUCT master)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'MED:'||RXNORM_CODE, 'Medication', ANY_VALUE(GENERIC_NAME),
  OBJECT_CONSTRUCT('rxnorm_code',RXNORM_CODE,'generic_name',ANY_VALUE(GENERIC_NAME),'brand_name',ANY_VALUE(BRAND_NAME),
    'strength',ANY_VALUE(STRENGTH),'dosage_form',ANY_VALUE(DOSAGE_FORM),'ndc_example',MIN(NDC))
FROM PHARMACY_OPS.RX.NDC_PRODUCT WHERE RXNORM_CODE IS NOT NULL
GROUP BY RXNORM_CODE;

-- Coverage: claims-side (from MEMBER)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'COV:'||m.MEMBER_ID, 'Coverage', m.PLAN_NAME,
  OBJECT_CONSTRUCT('coverage_id','COV:'||m.MEMBER_ID,'coverage_source','CLAIMS','patient_key',mm.MRN,
    'payer_name',m.PLAN_NAME,'plan_name',m.PLAN_NAME,'group_no',m.GROUP_NO,'member_id',m.MEMBER_ID,
    'subscriber_id',m.SUBSCRIBER_ID,'relationship',m.RELATIONSHIP,
    'effective_date',TO_VARCHAR(m.EFFECTIVE_DATE),'term_date',TO_VARCHAR(m.TERM_DATE))
FROM PAYER_CLAIMS.CLAIMS.MEMBER m
LEFT JOIN STG_MAP_MEMBER mm ON mm.MEMBER_ID = m.MEMBER_ID;

-- Coverage: EMR inline (from PATIENT_MASTER)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'COVEMR:'||p.MRN, 'Coverage', p.INS_PAYER_NAME,
  OBJECT_CONSTRUCT('coverage_id','COVEMR:'||p.MRN,'coverage_source','EMR','patient_key',p.MRN,
    'payer_name',p.INS_PAYER_NAME,'plan_name',p.INS_PAYER_NAME,'group_no',p.INS_GROUP,'member_id',p.INS_MEMBER_ID,
    'subscriber_id',NULL,'relationship',NULL,'effective_date',NULL,'term_date',NULL)
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p
WHERE p.INS_PAYER_NAME IS NOT NULL;

-- TBox: one node per ontology class (for hierarchy traversal UDFs)
INSERT INTO KG_NODE (NODE_ID, NODE_TYPE, NAME, PROPS)
SELECT 'CLASS:'||c.class_name, 'OntologyClass', c.class_name,
  OBJECT_CONSTRUCT('class_name',c.class_name,'parent',c.parent,'is_abstract',c.is_abstract)
FROM (
  SELECT * FROM (VALUES
    ('Entity',NULL,TRUE),('Person','Entity',TRUE),('Organization','Entity',TRUE),('Act','Entity',TRUE),('Concept','Entity',TRUE),
    ('Patient','Person',FALSE),('Practitioner','Person',FALSE),('RelatedPerson','Person',FALSE),
    ('Payer','Organization',FALSE),('Facility','Organization',FALSE),
    ('Encounter','Act',FALSE),('Claim','Act',FALSE),('ClaimLine','Act',FALSE),('MedicationRequest','Act',FALSE),
    ('MedicationDispense','Act',FALSE),('Observation','Act',FALSE),
    ('Condition','Concept',FALSE),('Procedure','Concept',FALSE),('Medication','Concept',FALSE),('ServiceSetting','Concept',FALSE),
    ('Location','Entity',FALSE),('Coverage','Entity',FALSE)
  ) AS t(class_name, parent, is_abstract)
) c;

-- ============================================================================
-- KG_EDGE LOADS
-- ============================================================================

-- subClassOf (TBox hierarchy)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:subClassOf:'||child, 'CLASS:'||child, 'CLASS:'||parent, 'subClassOf'
FROM (
  SELECT * FROM (VALUES
    ('Person','Entity'),('Organization','Entity'),('Act','Entity'),('Concept','Entity'),
    ('Patient','Person'),('Practitioner','Person'),('RelatedPerson','Person'),
    ('Payer','Organization'),('Facility','Organization'),
    ('Encounter','Act'),('Claim','Act'),('ClaimLine','Act'),('MedicationRequest','Act'),
    ('MedicationDispense','Act'),('Observation','Act'),
    ('Condition','Concept'),('Procedure','Concept'),('Medication','Concept'),('ServiceSetting','Concept'),
    ('Location','Entity'),('Coverage','Entity')
  ) AS t(child, parent)
);

-- patient_has_pcp
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:pcp:'||p.MRN, 'PT:'||p.MRN, 'PR:'||p.PCP_NPI, 'patient_has_pcp'
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p
JOIN CLINICAL_EMR.EHR.PHYSICIAN ph ON ph.NPI = p.PCP_NPI
WHERE p.PCP_NPI IS NOT NULL;

-- patient_has_coverage (claims + EMR)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:cov:CLAIMS:'||mm.MRN||':'||m.MEMBER_ID, 'PT:'||mm.MRN, 'COV:'||m.MEMBER_ID, 'patient_has_coverage',
       OBJECT_CONSTRUCT('coverage_source','CLAIMS')
FROM PAYER_CLAIMS.CLAIMS.MEMBER m JOIN STG_MAP_MEMBER mm ON mm.MEMBER_ID = m.MEMBER_ID;
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:cov:EMR:'||p.MRN, 'PT:'||p.MRN, 'COVEMR:'||p.MRN, 'patient_has_coverage',
       OBJECT_CONSTRUCT('coverage_source','EMR')
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p WHERE p.INS_PAYER_NAME IS NOT NULL;

-- coverage_with_payer (claims + EMR)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:covpay:CLAIMS:'||m.MEMBER_ID, 'COV:'||m.MEMBER_ID, 'PAYER:'||UPPER(REPLACE(TRIM(m.PLAN_NAME),' ','_')), 'coverage_with_payer'
FROM PAYER_CLAIMS.CLAIMS.MEMBER m WHERE m.PLAN_NAME IS NOT NULL;
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:covpay:EMR:'||p.MRN, 'COVEMR:'||p.MRN, 'PAYER:'||UPPER(REPLACE(TRIM(p.INS_PAYER_NAME),' ','_')), 'coverage_with_payer'
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p WHERE p.INS_PAYER_NAME IS NOT NULL;

-- coverage_subscriber_is (claims policy holder = the 'self' member on the SUBSCRIBER_ID)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:covsub:'||m.MEMBER_ID, 'COV:'||m.MEMBER_ID, 'PT:'||self_mm.MRN, 'coverage_subscriber_is',
       OBJECT_CONSTRUCT('relationship', self_m.RELATIONSHIP)
FROM PAYER_CLAIMS.CLAIMS.MEMBER m
JOIN PAYER_CLAIMS.CLAIMS.MEMBER self_m
     ON self_m.SUBSCRIBER_ID = m.SUBSCRIBER_ID AND LOWER(self_m.RELATIONSHIP) = 'self'
JOIN STG_MAP_MEMBER self_mm ON self_mm.MEMBER_ID = self_m.MEMBER_ID;

-- patient_has_related_person
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:kin:'||p.MRN, 'PT:'||p.MRN, 'RP:'||p.MRN, 'patient_has_related_person'
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p WHERE p.KIN_NAME IS NOT NULL;

-- related_person_resolves_to_patient (name-only match to an existing patient)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:kinres:'||p.MRN, 'RP:'||p.MRN, 'PT:'||rp.MRN, 'related_person_resolves_to_patient',
       OBJECT_CONSTRUCT('match_basis','name_only')
FROM CLINICAL_EMR.EHR.PATIENT_MASTER p
JOIN CLINICAL_EMR.EHR.PATIENT_MASTER rp
     ON UPPER(rp.FIRST_NAME||' '||rp.LAST_NAME) = UPPER(p.KIN_NAME) AND rp.MRN <> p.MRN
WHERE p.KIN_NAME IS NOT NULL;

-- patient_has_condition (problem list)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS, EFFECTIVE_START)
SELECT 'E:pcond:'||pl.PROBLEM_ID, 'PT:'||pl.MRN, 'CND:'||FN_ICD10_DOTTED(pl.ICD10_CODE), 'patient_has_condition',
       OBJECT_CONSTRUCT('status',pl.STATUS), pl.ONSET_DATE
FROM CLINICAL_EMR.EHR.PROBLEM_LIST pl WHERE pl.ICD10_CODE IS NOT NULL;

-- practitioner_works_at
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:works:'||ph.NPI, 'PR:'||ph.NPI, 'LOC:'||ph.DEPT_ID, 'practitioner_works_at'
FROM CLINICAL_EMR.EHR.PHYSICIAN ph WHERE ph.DEPT_ID IS NOT NULL;

-- location_within_facility
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:locfac:'||d.DEPT_ID, 'LOC:'||d.DEPT_ID,
       'FAC:'||UPPER(REPLACE(REPLACE(d.FACILITY_NAME,' ','_'),'''','')), 'location_within_facility'
FROM CLINICAL_EMR.EHR.DEPARTMENT d WHERE d.FACILITY_NAME IS NOT NULL;

-- encounter_of_patient
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, EFFECTIVE_START)
SELECT 'E:encpt:'||v.VISIT_ID, 'ENC:'||v.VISIT_ID, 'PT:'||v.MRN, 'encounter_of_patient', v.VISIT_DATE
FROM CLINICAL_EMR.EHR.VISIT v;

-- encounter_performed_by
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:encby:'||v.VISIT_ID, 'ENC:'||v.VISIT_ID, 'PR:'||pl.NPI, 'encounter_performed_by'
FROM CLINICAL_EMR.EHR.VISIT v JOIN STG_PHYS_LOCAL pl ON pl.PHYSICIAN_ID = v.PHYSICIAN_ID;

-- encounter_at_location
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:encloc:'||v.VISIT_ID, 'ENC:'||v.VISIT_ID, 'LOC:'||v.DEPT_ID, 'encounter_at_location'
FROM CLINICAL_EMR.EHR.VISIT v WHERE v.DEPT_ID IS NOT NULL;

-- encounter_diagnoses_condition
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:encdx:'||v.VISIT_ID, 'ENC:'||v.VISIT_ID, 'CND:'||FN_ICD10_DOTTED(v.PRIMARY_ICD10), 'encounter_diagnoses_condition'
FROM CLINICAL_EMR.EHR.VISIT v WHERE v.PRIMARY_ICD10 IS NOT NULL;

-- encounter_has_observation (vitals: exact; labs: date-inferred)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:encobsV:'||n.NODE_ID, 'ENC:'||n.PROPS:visit_id::STRING, n.NODE_ID, 'encounter_has_observation',
       OBJECT_CONSTRUCT('inferred',FALSE)
FROM KG_NODE n WHERE n.NODE_TYPE='Observation' AND n.PROPS:obs_kind::STRING='VITAL';
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:encobsL:'||n.NODE_ID||':'||v.VISIT_ID, 'ENC:'||v.VISIT_ID, n.NODE_ID, 'encounter_has_observation',
       OBJECT_CONSTRUCT('inferred',TRUE)
FROM KG_NODE n
JOIN CLINICAL_EMR.EHR.VISIT v
  ON v.MRN = n.PROPS:patient_key::STRING AND v.VISIT_DATE = TO_DATE(n.PROPS:obs_date::STRING)
WHERE n.NODE_TYPE='Observation' AND n.PROPS:obs_kind::STRING='LAB';

-- observation_of_patient
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:obspt:'||n.NODE_ID, n.NODE_ID, 'PT:'||n.PROPS:patient_key::STRING, 'observation_of_patient'
FROM KG_NODE n WHERE n.NODE_TYPE='Observation';

-- claim_for_patient
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, EFFECTIVE_START)
SELECT 'E:clmpt:'||c.CLAIM_ID, 'CLM:'||c.CLAIM_ID, 'PT:'||c.PATIENT_KEY, 'claim_for_patient', c.SERVICE_DATE
FROM STG_CLAIM c WHERE c.PATIENT_KEY IS NOT NULL;

-- claim_rendered_by
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:clmby:'||c.CLAIM_ID, 'CLM:'||c.CLAIM_ID, 'PR:'||c.RENDERING_NPI, 'claim_rendered_by'
FROM STG_CLAIM c
JOIN CLINICAL_EMR.EHR.PHYSICIAN ph ON ph.NPI = c.RENDERING_NPI;

-- claim_under_coverage
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:clmcov:'||c.CLAIM_ID, 'CLM:'||c.CLAIM_ID, 'COV:'||c.MEMBER_ID, 'claim_under_coverage'
FROM STG_CLAIM c WHERE c.MEMBER_ID IS NOT NULL;

-- claim_at_setting
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:clmset:'||c.CLAIM_ID, 'CLM:'||c.CLAIM_ID, 'SVC:'||c.POS_CODE, 'claim_at_setting'
FROM STG_CLAIM c WHERE c.POS_CODE IS NOT NULL;

-- claim_for_encounter (INFERRED: patient + rendering NPI + service_date = visit_date)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS, EFFECTIVE_START)
SELECT 'E:clmenc:'||c.CLAIM_ID, 'CLM:'||c.CLAIM_ID, 'ENC:'||v.VISIT_ID, 'claim_for_encounter',
       OBJECT_CONSTRUCT('match_basis','patient+npi+date','inferred',TRUE), c.SERVICE_DATE
FROM STG_CLAIM c
JOIN CLINICAL_EMR.EHR.VISIT v ON v.MRN = c.PATIENT_KEY AND v.VISIT_DATE = c.SERVICE_DATE
JOIN STG_PHYS_LOCAL pl ON pl.PHYSICIAN_ID = v.PHYSICIAN_ID AND pl.NPI = c.RENDERING_NPI;

-- claim_has_line
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:clmline:'||cl.CLAIM_ID||':'||cl.LINE_NO, 'CLM:'||cl.CLAIM_ID, 'CLL:'||cl.CLAIM_ID||':'||cl.LINE_NO, 'claim_has_line'
FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE cl;

-- claimline_involves_procedure
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:clproc:'||cl.CLAIM_ID||':'||cl.LINE_NO, 'CLL:'||cl.CLAIM_ID||':'||cl.LINE_NO, 'PROC:'||cl.CPT_CODE, 'claimline_involves_procedure'
FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE cl WHERE cl.CPT_CODE IS NOT NULL;

-- claimline_diagnoses_condition
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:cldx:'||cl.CLAIM_ID||':'||cl.LINE_NO, 'CLL:'||cl.CLAIM_ID||':'||cl.LINE_NO, 'CND:'||FN_ICD10_DOTTED(cl.DX_CODE), 'claimline_diagnoses_condition'
FROM PAYER_CLAIMS.CLAIMS.CLAIMS_LINE cl WHERE cl.DX_CODE IS NOT NULL;

-- medrequest_of_patient
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, EFFECTIVE_START)
SELECT 'E:mrpt:'||r.MED_ORDER_ID, 'MR:'||r.MED_ORDER_ID, 'PT:'||r.PATIENT_KEY, 'medrequest_of_patient', r.ORDER_DATE
FROM STG_MEDREQUEST r WHERE r.PATIENT_KEY IS NOT NULL;

-- medrequest_ordered_by
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:mrby:'||r.MED_ORDER_ID, 'MR:'||r.MED_ORDER_ID, 'PR:'||r.PHYSICIAN_NPI, 'medrequest_ordered_by'
FROM STG_MEDREQUEST r WHERE r.PHYSICIAN_NPI IS NOT NULL;

-- medrequest_for_medication (direct RxNorm or text-recovered)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:mrmed:'||r.MED_ORDER_ID, 'MR:'||r.MED_ORDER_ID, 'MED:'||r.RXNORM_RESOLVED, 'medrequest_for_medication',
       OBJECT_CONSTRUCT('rxnorm_was_null',r.RXNORM_WAS_NULL,'match_basis',IFF(r.RXNORM_WAS_NULL,'text_name_strength','direct_rxnorm'))
FROM STG_MEDREQUEST r WHERE r.RXNORM_RESOLVED IS NOT NULL;

-- medrequest_during_encounter (INFERRED: patient + ordering NPI + order_date = visit_date)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS, EFFECTIVE_START)
SELECT 'E:mrenc:'||r.MED_ORDER_ID, 'MR:'||r.MED_ORDER_ID, 'ENC:'||v.VISIT_ID, 'medrequest_during_encounter',
       OBJECT_CONSTRUCT('inferred',TRUE), r.ORDER_DATE
FROM STG_MEDREQUEST r
JOIN CLINICAL_EMR.EHR.VISIT v ON v.MRN = r.PATIENT_KEY AND v.VISIT_DATE = r.ORDER_DATE
JOIN STG_PHYS_LOCAL pl ON pl.PHYSICIAN_ID = v.PHYSICIAN_ID AND pl.NPI = r.PHYSICIAN_NPI;

-- dispense_of_patient
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, EFFECTIVE_START)
SELECT 'E:mdpt:'||d.FILL_ID, 'MD:'||d.FILL_ID, 'PT:'||d.PATIENT_KEY, 'dispense_of_patient', d.FILL_DATE
FROM STG_DISPENSE d WHERE d.PATIENT_KEY IS NOT NULL;

-- dispense_prescribed_by
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:mdby:'||d.FILL_ID, 'MD:'||d.FILL_ID, 'PR:'||d.PRESCRIBER_NPI, 'dispense_prescribed_by'
FROM STG_DISPENSE d
JOIN CLINICAL_EMR.EHR.PHYSICIAN ph ON ph.NPI = d.PRESCRIBER_NPI;

-- dispense_of_medication
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE)
SELECT 'E:mdmed:'||d.FILL_ID, 'MD:'||d.FILL_ID, 'MED:'||d.RXNORM_CODE, 'dispense_of_medication'
FROM STG_DISPENSE d WHERE d.RXNORM_CODE IS NOT NULL;

-- dispense_fulfills_request (INFERRED: patient + prescriber + drug + date proximity <= 60d)
INSERT INTO KG_EDGE (EDGE_ID, SRC_ID, DST_ID, EDGE_TYPE, PROPS)
SELECT 'E:mdfr:'||d.FILL_ID||':'||r.MED_ORDER_ID, 'MD:'||d.FILL_ID, 'MR:'||r.MED_ORDER_ID, 'dispense_fulfills_request',
       OBJECT_CONSTRUCT('match_basis', IFF(r.RXNORM_WAS_NULL,'patient+prescriber+date+name_recovered','patient+prescriber+date+rxnorm'))
FROM STG_DISPENSE d
JOIN STG_MEDREQUEST r
  ON r.PATIENT_KEY = d.PATIENT_KEY
 AND r.PHYSICIAN_NPI = d.PRESCRIBER_NPI
 AND r.RXNORM_RESOLVED = d.RXNORM_CODE
 AND ABS(DATEDIFF('day', r.ORDER_DATE, d.WRITTEN_DATE)) <= 60
QUALIFY ROW_NUMBER() OVER (PARTITION BY d.FILL_ID ORDER BY ABS(DATEDIFF('day', r.ORDER_DATE, d.WRITTEN_DATE))) = 1;


