USE SCHEMA CLINICAL_EMR.ONTOLOGY;

-- V_PATIENT: Typed view for Patient (KG path)
CREATE OR REPLACE VIEW V_PATIENT AS
SELECT
    NODE_ID,
    NAME,
    PROPS:mrn::STRING AS MRN,
    PROPS:member_id::STRING AS MEMBER_ID,
    PROPS:rx_member_id::STRING AS RX_MEMBER_ID,
    PROPS:ssn::STRING AS SSN,
    PROPS:full_name::STRING AS FULL_NAME,
    PROPS:first_name::STRING AS FIRST_NAME,
    PROPS:last_name::STRING AS LAST_NAME,
    PROPS:dob::DATE AS DOB,
    PROPS:gender::STRING AS GENDER,
    PROPS:city::STRING AS CITY,
    PROPS:state::STRING AS STATE,
    PROPS:zip::STRING AS ZIP,
    PROPS:phone::STRING AS PHONE,
    PROPS:source_systems::STRING AS SOURCE_SYSTEMS,
    PROPS
FROM KG_NODE
WHERE NODE_TYPE = 'Patient';

-- V_PRACTITIONER: Typed view for Practitioner (KG path)
CREATE OR REPLACE VIEW V_PRACTITIONER AS
