    PROPS:npi::STRING AS NPI,
    PROPS:full_name::STRING AS FULL_NAME,
    PROPS:name_emr::STRING AS NAME_EMR,
    PROPS:name_claims::STRING AS NAME_CLAIMS,
    PROPS:name_pharmacy::STRING AS NAME_PHARMACY,
    PROPS:specialty::STRING AS SPECIALTY,
    PROPS:specialty_raw_claims::STRING AS SPECIALTY_RAW_CLAIMS,
    PROPS:local_physician_id::NUMBER AS LOCAL_PHYSICIAN_ID,
    PROPS:dept_id::NUMBER AS DEPT_ID,
