-- ============================================================================
-- Layer 2: Ontology Metadata Tables for HEALTHCARE_ONTOLOGY
-- Generated: 2026-07-10 07:26 UTC
-- ============================================================================

USE SCHEMA CLINICAL_EMR.ONTOLOGY;

CREATE TABLE IF NOT EXISTS ONT_CLASS (
    CLASS_NAME          STRING NOT NULL PRIMARY KEY,
    PARENT_CLASS_NAME   STRING,
    IS_ABSTRACT         BOOLEAN DEFAULT FALSE,
    DESCRIPTION         STRING,
    ONTOLOGY_NAME       STRING DEFAULT 'HEALTHCARE_ONTOLOGY',
    TYPE_CLASS          STRING DEFAULT 'ANALYTICAL',
    CREATED_AT          TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP()
);

INSERT INTO ONT_CLASS (CLASS_NAME, PARENT_CLASS_NAME, IS_ABSTRACT, DESCRIPTION, TYPE_CLASS)
SELECT * FROM VALUES
    ('Entity', NULL, TRUE, 'Abstract root of the healthcare ontology. All classes descend from Entity.', 'ANALYTICAL'),
    ('Person', 'Entity', TRUE, 'Abstract superclass for people: patients, practitioners, and related persons.', 'ANALYTICAL'),
    ('Organization', 'Entity', TRUE, 'Abstract superclass for organizational entities: healthcare facilities and payers.', 'ANALYTICAL'),
    ('Act', 'Entity', TRUE, 'Abstract superclass for clinical and administrative events/activities: encounters, claims, medication requests/dispenses, observations.', 'ANALYTICAL'),
    ('Concept', 'Entity', TRUE, 'Abstract superclass for coded reference concepts: conditions (ICD-10), procedures (CPT), medications (RxNorm), service settings (CMS POS).', 'ANALYTICAL'),
    ('Patient', 'Person', FALSE, 'A person receiving care. Identity resolved across EHR PATIENT_MASTER, claims MEMBER, and pharmacy SUBSCRIBER via degrading hierarchy (INS_MEMBER_ID -> SSN -> name+DOB). Handles nicknames (Bob=Robert) and gender code normalization (1/2 -> M/F). Address folded in as attributes.', 'OPERATIONAL'),
    ('Practitioner', 'Person', FALSE, 'A clinician. Identity resolved on universal NPI across EHR PHYSICIAN, claims RENDERING_PROVIDER, and pharmacy PRESCRIBER. Reconciles three name spellings (Sarah Chen, MD / CHEN, SARAH / S CHEN). Specialty kept as normalized attribute (EMR canonical wins) with raw claims variant retained.', 'OPERATIONAL'),
    ('RelatedPerson', 'Person', FALSE, 'Next-of-kin / emergency contact for a patient (name, relationship, phone) from PATIENT_MASTER KIN_* columns. At most one per patient. Some kin are themselves patients (spousal cross-references) and are linked via related_person_resolves_to_patient.', 'OPERATIONAL'),
    ('Payer', 'Organization', FALSE, 'An insurance payer / plan-product. Values are plan/product names (e.g. Buckeye Health Plan, Medicare). Simplification: Payer is grained at plan-name; GROUP_NO is carried as a Coverage attribute. Derived from distinct plan/payer names in PATIENT_MASTER, MEMBER, CLAIMS_LINE.', 'OPERATIONAL'),
    ('Facility', 'Organization', FALSE, 'A healthcare facility / care organization (e.g. Riverside Medical Center). Derived from distinct DEPARTMENT.FACILITY_NAME. Departments (Location) sit within a Facility.', 'OPERATIONAL'),
    ('Encounter', 'Act', FALSE, 'A clinical encounter/visit from EHR VISIT (overloaded: encounter + provider + location + primary condition + vitals).', 'OPERATIONAL'),
    ('Claim', 'Act', FALSE, 'A payer claim header (one per CLAIM_ID), extracted from the overloaded CLAIMS_LINE table.', 'OPERATIONAL'),
    ('ClaimLine', 'Act', FALSE, 'A single claim service line (CLAIM_ID + LINE_NO) carrying a CPT procedure, a diagnosis code, and financials. Extracted from CLAIMS_LINE.', 'OPERATIONAL'),
    ('MedicationRequest', 'Act', FALSE, 'A prescription/order for a drug from EHR MEDICATION. Its canonical Medication is resolved independently via DRUG_NAME -> NDC_PRODUCT.GENERIC_NAME+STRENGTH text match when RXNORM_CODE is NULL (non-circular).', 'OPERATIONAL'),
    ('MedicationDispense', 'Act', FALSE, 'A pharmacy dispensing event from PHARMACY_FILL (overloaded: request + dispense + medication + patient + prescriber).', 'OPERATIONAL'),
    ('Observation', 'Act', FALSE, 'A clinical measurement. Unifies wide vitals columns in VISIT (BP, weight, A1c) and wide analyte columns in LAB_RESULTS (glucose, HbA1c, LDL, creatinine, eGFR) into one uniform unpivoted set. Vitals tie to a specific Encounter row; labs tie reliably only to Patient (Encounter link is date-inferred).', 'OPERATIONAL'),
    ('Condition', 'Concept', FALSE, 'A canonical diagnosis concept. Canonical form = DOTTED ICD-10 (E11.9); claims DX_CODE (E119, no dot) is normalized by re-inserting the dot after the 3rd character. Aggregated from PROBLEM_LIST (with SNOMED), VISIT.PRIMARY_ICD10, and CLAIMS_LINE.DX_CODE.', 'OPERATIONAL'),
    ('Procedure', 'Concept', FALSE, 'A canonical procedure concept keyed on CPT code, derived from distinct CPT codes in CLAIMS_LINE.', 'OPERATIONAL'),
    ('Medication', 'Concept', FALSE, 'A canonical drug concept keyed on RxNorm. Master source is NDC_PRODUCT (holds the RxNorm<->NDC crosswalk and GENERIC_NAME/STRENGTH used for text matching); resolves EHR MEDICATION orders and PHARMACY_FILL dispenses, including NULL-RxNorm recovery.', 'OPERATIONAL'),
    ('ServiceSetting', 'Concept', FALSE, 'A CMS Place-of-Service concept (a TYPE of setting, not a physical place), e.g. POS 11 = Office. Sourced from PLACE_OF_SERVICE. Deliberately distinct from Location so a code category and a concrete department never collapse into one node.', 'OPERATIONAL'),
    ('Location', 'Entity', FALSE, 'A concrete physical care location / clinical department from EHR DEPARTMENT (carries its own address). Sits within a Facility via location_within_facility. Distinct from ServiceSetting (a POS code category).', 'OPERATIONAL'),
    ('Coverage', 'Entity', FALSE, 'An insurance coverage/policy instance (member + plan + group + subscriber + effective dates). Nested inline in PATIENT_MASTER (EMR view, no SUBSCRIBER_ID) and in MEMBER/CLAIMS_LINE (claims view). Family policies share a SUBSCRIBER_ID (e.g. SUBFAM1). EMR coverage reconciled to claims by MEMBER_ID.', 'OPERATIONAL')
AS t(CLASS_NAME, PARENT_CLASS_NAME, IS_ABSTRACT, DESCRIPTION, TYPE_CLASS);

CREATE TABLE IF NOT EXISTS ONT_RELATION_DEF (
    REL_NAME            STRING NOT NULL PRIMARY KEY,
    DOMAIN_CLASS        STRING NOT NULL,
    RANGE_CLASS         STRING NOT NULL,
    CARDINALITY         STRING DEFAULT 'N:N',
    IS_HIERARCHICAL     BOOLEAN DEFAULT FALSE,
    IS_TRANSITIVE       BOOLEAN DEFAULT FALSE,
    INVERSE_REL_NAME    STRING,
    DESCRIPTION         STRING,
    ONTOLOGY_NAME       STRING DEFAULT 'HEALTHCARE_ONTOLOGY'
);

INSERT INTO ONT_RELATION_DEF (REL_NAME, DOMAIN_CLASS, RANGE_CLASS, CARDINALITY, IS_HIERARCHICAL, IS_TRANSITIVE, INVERSE_REL_NAME, DESCRIPTION)
SELECT * FROM VALUES
    ('act_involves_patient', 'Act', 'Patient', 'N:1', FALSE, FALSE, 'patient_involved_in_act', 'Abstract relation: any clinical/administrative Act involves a Patient. Parent of encounter/claim/medication/observation patient links.'),
    ('act_involves_practitioner', 'Act', 'Practitioner', 'N:1', FALSE, FALSE, 'practitioner_involved_in_act', 'Abstract relation: any clinical/administrative Act involves a Practitioner. Parent of encounter/claim/medication practitioner links.'),
    ('patient_has_pcp', 'Patient', 'Practitioner', 'N:1', FALSE, FALSE, 'pcp_of_patient', 'Patient''s primary care provider. From PATIENT_MASTER.PCP_NPI resolved to a Practitioner by NPI.'),
    ('patient_has_coverage', 'Patient', 'Coverage', 'N:M', FALSE, FALSE, 'coverage_of_patient', 'Links a Patient to an insurance Coverage. Populated from EMR inline coverage (PATIENT_MASTER INS_*, reconciled to claims by MEMBER_ID) and claims MEMBER; enables EMR-vs-claims coverage reconciliation.'),
    ('coverage_with_payer', 'Coverage', 'Payer', 'N:1', FALSE, FALSE, 'payer_of_coverage', 'The Payer (plan/product) sponsoring a Coverage.'),
    ('coverage_subscriber_is', 'Coverage', 'Patient', 'N:1', FALSE, FALSE, 'subscriber_of_coverage', 'The subscriber (policyholder) Patient of a Coverage. Claims-side only: subscriber is the MEMBER with RELATIONSHIP=''self'' sharing the SUBSCRIBER_ID. Family members share a SUBSCRIBER_ID (e.g. SUBFAM1), enabling family-policy roster queries.'),
    ('patient_has_related_person', 'Patient', 'RelatedPerson', '1:0..1', FALSE, FALSE, 'related_person_of_patient', 'Patient''s next-of-kin/emergency contact (name, relationship, phone) from PATIENT_MASTER KIN_* columns. At most one per patient.'),
    ('related_person_resolves_to_patient', 'RelatedPerson', 'Patient', 'N:0..1', FALSE, FALSE, 'patient_is_related_person', 'Entity-resolution link: when a next-of-kin is themselves a patient in the system (e.g. James Johnson and Linda Williams each list the other as spouse), the RelatedPerson resolves to an existing Patient. Match is NAME-ONLY (KIN_NAME -> Patient.FULL_NAME) since KIN_* carries no DOB, so it is lower-confidence; optionally corroborated by the reciprocal spousal link (each lists the other) and shared address/phone. Prevents duplicate person identities.'),
    ('patient_has_condition', 'Patient', 'Condition', 'N:M', FALSE, FALSE, 'condition_of_patient', 'A Patient''s diagnosed condition from PROBLEM_LIST, keyed on canonical dotted ICD-10.'),
    ('practitioner_works_at', 'Practitioner', 'Location', 'N:1', FALSE, FALSE, 'location_employs_practitioner', 'The Location/department a Practitioner is affiliated with (PHYSICIAN.DEPT_ID).'),
    ('location_within_facility', 'Location', 'Facility', 'N:1', FALSE, FALSE, 'facility_contains_location', 'Part-of link: a Location (clinical department) sits within a Facility (DEPARTMENT.FACILITY_NAME).'),
    ('encounter_of_patient', 'Encounter', 'Patient', 'N:1', FALSE, FALSE, 'patient_had_encounter', 'The Patient seen in an Encounter (VISIT.MRN resolved to canonical patient).'),
    ('encounter_performed_by', 'Encounter', 'Practitioner', 'N:1', FALSE, FALSE, 'practitioner_performed_encounter', 'The Practitioner who performed an Encounter (VISIT.PHYSICIAN_ID local id resolved to NPI).'),
    ('encounter_at_location', 'Encounter', 'Location', 'N:1', FALSE, FALSE, 'location_hosted_encounter', 'The concrete Location (department) where an Encounter occurred (VISIT.DEPT_ID).'),
    ('encounter_diagnoses_condition', 'Encounter', 'Condition', 'N:1', FALSE, FALSE, 'condition_addressed_in_encounter', 'The primary Condition addressed in an Encounter (VISIT.PRIMARY_ICD10 canonicalized to dotted ICD-10).'),
    ('encounter_has_observation', 'Encounter', 'Observation', '1:N', FALSE, FALSE, 'observation_in_encounter', 'Observations captured for an Encounter. Exact for VISIT vitals (same row); INFERRED/optional for labs (LAB_RESULTS has only MRN+COLLECT_DATE, attached by COLLECT_DATE approx VISIT_DATE). observation_of_patient is the always-true edge for labs.'),
    ('observation_of_patient', 'Observation', 'Patient', 'N:1', FALSE, FALSE, 'patient_has_observation', 'The Patient an Observation was measured on (vitals via VISIT, labs via LAB_RESULTS.MRN). Always-true edge for every observation.'),
    ('claim_for_patient', 'Claim', 'Patient', 'N:1', FALSE, FALSE, 'patient_has_claim', 'The Patient a Claim is for (CLAIMS_LINE.MEMBER_ID resolved to canonical patient).'),
    ('claim_rendered_by', 'Claim', 'Practitioner', 'N:1', FALSE, FALSE, 'practitioner_rendered_claim', 'The Practitioner who rendered the service on a Claim (CLAIMS_LINE.RENDERING_NPI).'),
    ('claim_under_coverage', 'Claim', 'Coverage', 'N:1', FALSE, FALSE, 'coverage_paid_claim', 'The Coverage that adjudicated/paid a Claim (member + plan).'),
    ('claim_at_setting', 'Claim', 'ServiceSetting', 'N:1', FALSE, FALSE, 'setting_of_claim', 'The CMS place-of-service setting for a Claim (CLAIMS_LINE.POS_CODE -> ServiceSetting, e.g. 11=Office). A code category, not a physical Location.'),
    ('claim_for_encounter', 'Claim', 'Encounter', 'N:1', FALSE, FALSE, 'encounter_generated_claim', 'INFERRED cross-world link (no FK exists in the raw schema): aligns a payer Claim to the clinical Encounter that generated it, matched on resolved Patient + Practitioner (NPI) + SERVICE_DATE = VISIT_DATE. This is the flagship ontology-added edge bridging clinical and payer systems.'),
    ('claim_has_line', 'Claim', 'ClaimLine', '1:N', FALSE, FALSE, 'line_of_claim', 'Decomposes a Claim into its service lines (ClaimLine).'),
    ('claimline_involves_procedure', 'ClaimLine', 'Procedure', 'N:1', FALSE, FALSE, 'procedure_on_claimline', 'The CPT Procedure billed on a ClaimLine.'),
    ('claimline_diagnoses_condition', 'ClaimLine', 'Condition', 'N:1', FALSE, FALSE, 'condition_on_claimline', 'The diagnosis Condition on a ClaimLine (DX_CODE, dot-less ICD-10, normalized to dotted canonical to match EMR).'),
    ('medrequest_of_patient', 'MedicationRequest', 'Patient', 'N:1', FALSE, FALSE, 'patient_has_medrequest', 'The Patient a medication order was written for (MEDICATION.MRN resolved).'),
    ('medrequest_ordered_by', 'MedicationRequest', 'Practitioner', 'N:1', FALSE, FALSE, 'practitioner_ordered_medrequest', 'The Practitioner who ordered a medication (MEDICATION.PHYSICIAN_ID local id resolved to NPI).'),
    ('medrequest_for_medication', 'MedicationRequest', 'Medication', 'N:1', FALSE, FALSE, 'medication_ordered_in_request', 'The canonical Medication (RxNorm) ordered. Resolved INDEPENDENTLY (non-circular): if MEDICATION.RXNORM_CODE is present use it directly; if NULL, match DRUG_NAME to NDC_PRODUCT.GENERIC_NAME + STRENGTH by text to recover the RxNorm.'),
    ('medrequest_during_encounter', 'MedicationRequest', 'Encounter', 'N:0..1', FALSE, FALSE, 'encounter_has_medrequest', 'INFERRED link: a medication order placed during a clinical Encounter, matched on resolved Patient + ordering Practitioner (NPI) + ORDER_DATE = VISIT_DATE.'),
    ('dispense_of_patient', 'MedicationDispense', 'Patient', 'N:1', FALSE, FALSE, 'patient_has_dispense', 'The Patient a fill was dispensed to (PHARMACY_FILL.RX_MEMBER_ID resolved via SUBSCRIBER SSN/name+DOB; RX_MEMBER_ID is NOT the claims MEMBER_ID).'),
    ('dispense_prescribed_by', 'MedicationDispense', 'Practitioner', 'N:1', FALSE, FALSE, 'practitioner_prescribed_dispense', 'The Practitioner who prescribed a dispensed fill (PHARMACY_FILL.PRESCRIBER_ID = NPI).'),
    ('dispense_of_medication', 'MedicationDispense', 'Medication', 'N:1', FALSE, FALSE, 'medication_dispensed_in', 'The canonical Medication dispensed (PHARMACY_FILL.NDC -> NDC_PRODUCT.RXNORM_CODE).'),
    ('dispense_fulfills_request', 'MedicationDispense', 'MedicationRequest', 'N:1', FALSE, FALSE, 'request_fulfilled_by_dispense', 'INFERRED link from a pharmacy dispense back to the EMR order it fulfills. Matched on resolved Patient + prescriber/orderer (NPI) + date proximity (WRITTEN_DATE approx ORDER_DATE) + same drug. Drug match uses RxNorm when available; for NULL-RxNorm orders it falls back to name-to-brand/generic text matching (DRUG_NAME <-> GENERIC_NAME/BRAND + STRENGTH).')
AS t(REL_NAME, DOMAIN_CLASS, RANGE_CLASS, CARDINALITY, IS_HIERARCHICAL, IS_TRANSITIVE, INVERSE_REL_NAME, DESCRIPTION);

