    CLASS_NAME          STRING,
    PROP_NAME           STRING,
    DATA_TYPE           STRING,
    SHARED_PROP_NAME    STRING,
    IS_REQUIRED         BOOLEAN DEFAULT FALSE,
    IS_INDEXED          BOOLEAN DEFAULT FALSE,
    DESCRIPTION         STRING,
    PRIMARY KEY (CLASS_NAME, PROP_NAME)
);

