    STATUS              STRING,
    RESULT_MSG          STRING,
    INVOKED_BY          STRING,
    INVOKED_AT          TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP(),
    COMPLETED_AT        TIMESTAMP_NTZ
);

