USE SCHEMA CLINICAL_EMR.ONTOLOGY;

-- VW_ONT_PATIENT: Entity view for Patient (KG path)
CREATE OR REPLACE VIEW VW_ONT_PATIENT AS
SELECT
    NODE_ID AS ENTITY_ID,
    NODE_TYPE AS ENTITY_TYPE,
    NAME AS ENTITY_NAME,
    PROPS
FROM KG_NODE
WHERE NODE_TYPE = 'Patient';

-- VW_ONT_PRACTITIONER: Entity view for Practitioner (KG path)
CREATE OR REPLACE VIEW VW_ONT_PRACTITIONER AS
SELECT
    NODE_ID AS ENTITY_ID,
    NODE_TYPE AS ENTITY_TYPE,
    NAME AS ENTITY_NAME,
    PROPS
FROM KG_NODE
WHERE NODE_TYPE = 'Practitioner';

-- VW_ONT_RELATEDPERSON: Entity view for RelatedPerson (KG path)
CREATE OR REPLACE VIEW VW_ONT_RELATEDPERSON AS
