-- ============================================================================
-- Layer 2b: Upstream provenance + identity-resolution metadata
-- Answers the "about the ontology itself" questions (Q7, Q8, Q9): which real
-- source tables/columns feed each class and which identifier systems resolve
-- them. Run after 03 (ONT_OBJECT_SOURCE must exist).
-- ============================================================================
USE SCHEMA CLINICAL_EMR.ONTOLOGY;

-- Upstream source tables per class (the generator seeded KG_NODE projections;
-- these rows record the TRUE originating tables across the 3 source systems).
INSERT INTO ONT_OBJECT_SOURCE (ONTOLOGY_NAME, OBJ_TYPE, SOURCE_TABLE, FILTER_SQL, MAPPING)
SELECT 'HEALTHCARE_ONTOLOGY', OBJ_TYPE, SOURCE_TABLE, NULL, PARSE_JSON(MAPPING_JSON)
FROM VALUES
  ('Patient','CLINICAL_EMR.EHR.PATIENT_MASTER','{"role":"anchor/master","keys":"MRN, SSN, INS_MEMBER_ID, FIRST/LAST/DOB","note":"canonical PATIENT_KEY = MRN"}'),
  ('Patient','PAYER_CLAIMS.CLAIMS.MEMBER','{"role":"claims identity","keys":"MEMBER_ID, MEMBER_SSN, MEMBER_NAME, DOB","link":"INS_MEMBER_ID=MEMBER_ID (strong)"}'),
  ('Patient','PHARMACY_OPS.RX.SUBSCRIBER','{"role":"pharmacy identity","keys":"RX_MEMBER_ID, PATIENT_SSN, PATIENT_NAME(nickname), DOB","link":"SSN then name+DOB (weak)"}'),
  ('Practitioner','CLINICAL_EMR.EHR.PHYSICIAN','{"role":"anchor","keys":"NPI, PHYSICIAN_ID(local), FULL_NAME, SPECIALTY"}'),
  ('Practitioner','PAYER_CLAIMS.CLAIMS.RENDERING_PROVIDER','{"role":"claims","keys":"RENDERING_NPI, PROVIDER_NAME(LAST, FIRST), PROVIDER_TYPE","link":"NPI"}'),
  ('Practitioner','PHARMACY_OPS.RX.PRESCRIBER','{"role":"pharmacy","keys":"PRESCRIBER_ID(=NPI), PRESCRIBER_NAME(S CHEN), DEA_NUMBER","link":"NPI"}'),
  ('RelatedPerson','CLINICAL_EMR.EHR.PATIENT_MASTER','{"role":"nested","keys":"KIN_NAME, KIN_RELATION, KIN_PHONE"}'),
  ('Payer','PAYER_CLAIMS.CLAIMS.MEMBER','{"keys":"PLAN_NAME"}'),
  ('Payer','CLINICAL_EMR.EHR.PATIENT_MASTER','{"keys":"INS_PAYER_NAME (inline)"}'),
  ('Payer','PAYER_CLAIMS.CLAIMS.CLAIMS_LINE','{"keys":"PLAN_NAME (inline)"}'),
  ('Facility','CLINICAL_EMR.EHR.DEPARTMENT','{"keys":"FACILITY_NAME (distinct)"}'),
  ('Location','CLINICAL_EMR.EHR.DEPARTMENT','{"keys":"DEPT_ID, DEPT_NAME, ADDRESS"}'),
  ('ServiceSetting','PAYER_CLAIMS.CLAIMS.PLACE_OF_SERVICE','{"keys":"POS_CODE, POS_DESCRIPTION"}'),
  ('Encounter','CLINICAL_EMR.EHR.VISIT','{"keys":"VISIT_ID","overloaded":"encounter+provider+location+dx+vitals"}'),
  ('Claim','PAYER_CLAIMS.CLAIMS.CLAIMS_LINE','{"keys":"CLAIM_ID (grouped)"}'),
  ('ClaimLine','PAYER_CLAIMS.CLAIMS.CLAIMS_LINE','{"keys":"CLAIM_ID+LINE_NO"}'),
  ('MedicationRequest','CLINICAL_EMR.EHR.MEDICATION','{"keys":"MED_ORDER_ID","note":"RXNORM_CODE may be NULL; recovered via DRUG_NAME->NDC_PRODUCT text match"}'),
  ('MedicationDispense','PHARMACY_OPS.RX.PHARMACY_FILL','{"keys":"FILL_ID, NDC","overloaded":"request+dispense+medication+patient+prescriber"}'),
  ('Observation','CLINICAL_EMR.EHR.VISIT','{"role":"vitals(wide)","keys":"BP_SYSTOLIC/DIASTOLIC, WEIGHT_KG, A1C_PCT","transform":"unpivot"}'),
  ('Observation','CLINICAL_EMR.EHR.LAB_RESULTS','{"role":"labs(wide)","keys":"GLUCOSE, HBA1C, LDL, CREATININE, EGFR","transform":"unpivot"}'),
  ('Condition','CLINICAL_EMR.EHR.PROBLEM_LIST','{"keys":"ICD10_CODE(dotted), SNOMED_CODE","canonical":"dotted ICD-10"}'),
  ('Condition','CLINICAL_EMR.EHR.VISIT','{"keys":"PRIMARY_ICD10(dotted)"}'),
  ('Condition','PAYER_CLAIMS.CLAIMS.CLAIMS_LINE','{"keys":"DX_CODE(no dot -> dotted)"}'),
  ('Procedure','PAYER_CLAIMS.CLAIMS.CLAIMS_LINE','{"keys":"CPT_CODE, CPT_DESC (distinct)"}'),
  ('Medication','PHARMACY_OPS.RX.NDC_PRODUCT','{"role":"master crosswalk","keys":"RXNORM_CODE<->NDC, GENERIC_NAME, STRENGTH"}'),
  ('Medication','CLINICAL_EMR.EHR.MEDICATION','{"role":"orders","keys":"RXNORM_CODE (some NULL)"}'),
  ('Medication','PHARMACY_OPS.RX.PHARMACY_FILL','{"role":"dispenses","keys":"NDC -> RxNorm"}'),
  ('Coverage','PAYER_CLAIMS.CLAIMS.MEMBER','{"role":"claims","keys":"MEMBER_ID, PLAN_NAME, GROUP_NO, SUBSCRIBER_ID"}'),
  ('Coverage','CLINICAL_EMR.EHR.PATIENT_MASTER','{"role":"EMR inline","keys":"INS_PAYER_NAME, INS_MEMBER_ID, INS_GROUP","reconcile":"by MEMBER_ID"}')
AS v(OBJ_TYPE, SOURCE_TABLE, MAPPING_JSON);

-- Identity-resolution rules (degrading-confidence crosswalks the ontology applies)
CREATE TABLE IF NOT EXISTS ONT_IDENTITY_RULE (
    ONTOLOGY_NAME  STRING DEFAULT 'HEALTHCARE_ONTOLOGY',
    CLASS_NAME     STRING,
    PRIORITY       NUMBER,
    ID_SYSTEM      STRING,
    MATCH_KEYS     STRING,
    CONFIDENCE     STRING,
    DESCRIPTION    STRING,
    CREATED_AT     TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP()
);

INSERT INTO ONT_IDENTITY_RULE (CLASS_NAME, PRIORITY, ID_SYSTEM, MATCH_KEYS, CONFIDENCE, DESCRIPTION)
SELECT * FROM VALUES
  ('Patient',1,'INS_MEMBER_ID','PATIENT_MASTER.INS_MEMBER_ID = MEMBER.MEMBER_ID','strong','Primary cross-system patient link (EMR <-> claims).'),
  ('Patient',2,'SSN','PATIENT_MASTER.SSN = MEMBER.MEMBER_SSN = SUBSCRIBER.PATIENT_SSN','medium','Fallback when member id absent; SSN may be NULL in pharmacy.'),
  ('Patient',3,'NAME_DOB','last name + DOB (nickname-tolerant: Bob=Robert, Beth=Elizabeth)','weak','Last-resort for NULL-SSN pharmacy rows.'),
  ('Practitioner',1,'NPI','PHYSICIAN.NPI = RENDERING_PROVIDER.RENDERING_NPI = PRESCRIBER.PRESCRIBER_ID','strong','Universal practitioner identifier across all three systems.'),
  ('Medication',1,'RXNORM','MEDICATION.RXNORM_CODE = NDC_PRODUCT.RXNORM_CODE = (PHARMACY_FILL.NDC -> RxNorm)','strong','Canonical drug key.'),
  ('Medication',2,'NDC_CROSSWALK','PHARMACY_FILL.NDC -> NDC_PRODUCT.RXNORM_CODE','strong','Recovers RxNorm for dispenses keyed by NDC.'),
  ('Medication',3,'NAME_STRENGTH','MEDICATION.DRUG_NAME -> NDC_PRODUCT.GENERIC_NAME + STRENGTH','medium','Recovers RxNorm for EMR orders where RXNORM_CODE is NULL.'),
  ('Condition',1,'ICD10_DOTTED','dotted ICD-10 canonical (claims DX_CODE gets dot re-inserted after char 3)','strong','Aligns E11.9 (EMR) with E119 (claims).'),
  ('Location',1,'POS_VS_DEPT','DEPARTMENT (physical) kept distinct from PLACE_OF_SERVICE (POS category)','n/a','ServiceSetting models POS; Location models departments.')
AS v(CLASS_NAME, PRIORITY, ID_SYSTEM, MATCH_KEYS, CONFIDENCE, DESCRIPTION);
